import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def future_cost_estimation(cur_truck_pos, customer_pos, window_start, window_end, unvisited_customers, current_time, truck_speed):
        distance = np.linalg.norm(customer_pos - cur_truck_pos)
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time

        feasible_visits_after = sum(1 for pos, (start, end) in zip(unvisited_customers, time_windows) 
                                    if arrival_time <= end and np.linalg.norm(pos - customer_pos) / truck_speed + arrival_time <= end)

        waiting_time = max(0, window_start - arrival_time)

        if arrival_time > window_end:
            return float('inf')

        score = distance + waiting_time - feasible_visits_after
        return score

    best_score = float('inf')
    best_node = None

    for index, customer in enumerate(unvisited_customers):
        customer_pos = np.array(customer)
        window_start, window_end = time_windows[index]

        score = future_cost_estimation(cur_truck_pos, customer_pos, window_start, window_end, unvisited_customers, current_time, truck_speed)

        if score < best_score:
            best_score = score
            best_node = index

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_score(customer_pos, time_window, current_time):
        distance = euclidean_distance(cur_truck_pos, customer_pos)
        arrival_time = current_time + distance / truck_speed
        wait_time = max(0, time_window[0] - arrival_time)

        if arrival_time > time_window[1]:
            return float('-inf')

        urgency = max(0, 1 / (time_window[1] - current_time + 1e-5))
        distance_to_depot = euclidean_distance(customer_pos, depot_pos)
        score = -distance + urgency - wait_time + (-distance_to_depot * 0.1)
        return score

    scores = [calculate_score(unvisited_customers[i], time_windows[i], current_time) for i in range(len(unvisited_customers))]
    best_node = max(range(len(unvisited_customers)), key=lambda i: scores[i])

    return best_node

import numpy as np

def euclidean_distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    best_priority = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time

        start_window, end_window = time_windows[idx]

        if arrival_time > end_window:
            continue  # Skip customers that cannot be reached within their time window

        waiting_time = max(0, start_window - arrival_time)
        urgency = (end_window - current_time) / truck_speed

        priority = travel_time + waiting_time + urgency

        if priority < best_priority:
            best_priority = priority
            best_node = idx

    return best_node
